import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { API_MOVIE, API_TV, API_KEY } from '../constant';
import { FiChevronLeft, FiChevronRight } from 'react-icons/fi';

const Video = (props) => {

  const { id, name } = props;
  const [data, setData] = useState([]);

  let api;
  switch (name) {
    case 'movie':
      api = API_MOVIE;
      break;

    case 'tv':
      api = API_TV;
      break;

    default:
      break;
  }

  useEffect(() => {
    const getData = async () => {
      await fetch(api + id + '/videos?api_key=' + API_KEY)
        .then((response) => {
          return response.json();
        })
        .then((data) => {
          setData(data.results);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [api, id]);

  const ref = useRef(null);

  const scrollRight = (scrollOffset) => {
    ref.current.scrollLeft -= scrollOffset;
  };

  const scrollLeft = (scrollOffset) => {
    ref.current.scrollLeft += scrollOffset;
  };

  return (
    <div className="mt-5">
      {data.length > 0 ?
        <div className="position-relative">
          <h2>Videos</h2>
          <button className="btn btn-secondary position-absolute scroll-button1" onClick={() => scrollRight(500)}><FiChevronLeft /></button>
          <button className="btn btn-secondary position-absolute scroll-button2" onClick={() => scrollLeft(500)}><FiChevronRight /></button>
          <div className="d-flex flex-row" ref={ref}>
            {data.map((dataRow, index) => (
              <Link key={index} className="card-link" to='/movieshub/'>
                <div className="card" key={index}>
                  <div className="card-body">
                    <div className="card-text">
                      <iframe src={"https://www.youtube.com/embed/" + dataRow.key} title={dataRow.name} frameBorder="0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe>
                      <div>{dataRow.name ? dataRow.name : dataRow.title}</div>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div> : ''}
    </div>
  )
}

export default Video
